const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const xss = require('xss-clean');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet()); // Sets various HTTP headers for security
class ValidationError extends Error {
  constructor(message, statusCode = 400) {
    super(message);
    this.statusCode = statusCode;
    this.name = 'ValidationError';
  }
}

// Rate limiting to prevent abuse
class AuthenticationError extends Error {
  constructor(message) {
    super(message);
    this.statusCode = 401;
    this.name = 'AuthenticationError';
  }
}

app.use(rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: {
    error: 'Too many requests from this IP, please try again later.',
  },
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
}));

// Parse JSON with size limit to prevent payload attacks
app.use(express.json({
  limit: '10kb', // Limit request body size
  verify: (req, res, buf) => {
    // Additional verification if needed
    req.rawBody = buf;
  }
}));

// Data sanitization against XSS
app.use(xss());

// Enable CORS with restrictions
app.use(cors({
  origin: process.env.WHITELISTED_DOMAINS || 'https://yourdomain.com',
  credentials: true
}));

// Request timeout to prevent denial of service
app.use((req, res, next) => {
  req.setTimeout(30000, () => { // 30 second timeout
    res.status(408).json({
      error: 'Request timeout'
    });
  });
  next();
});

// Input validation middleware
const validateQueryParams = (req, res, next) => {
  try {
    // Validate and sanitize query parameters
    if (req.query && typeof req.query === 'object') {
      for (const [key, value] of Object.entries(req.query)) {
        // Check for potential malicious patterns
        if (typeof value === 'string' && (value.includes('javascript:') || 
           value.includes('vbscript:') || 
           value.includes('<script') ||
           value.includes('onerror=') ||
           value.length > 1000)) { // Arbitrary length limit
          throw new ValidationError(`Invalid query parameter: ${key}`);
        }
      }
    }
    next();
  } catch (error) {
    next(error);
  }
};

// Use input validation middleware
app.use(validateQueryParams);

// Health check route with error handling
app.get('/health', (req, res, next) => {
  try {
    // Validate request
    if (req.headers['user-agent']?.toLowerCase().includes('nmap') ||
        req.headers['user-agent']?.toLowerCase().includes('nessus')) {
      return res.status(403).json({
        error: 'Forbidden'
      });
    }

    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    next(error);
  }
});

// Users route with validation
app.get('/users', (req, res, next) => {
  try {
    // Example of query parameter validation
    const page = req.query.page ? parseInt(req.query.page) : 1;
    const limit = req.query.limit ? parseInt(req.query.limit) : 10;

    // Validate parameters
    if (page < 1 || limit < 1 || limit > 100) {
      throw new ValidationError('Invalid pagination parameters');
    }

    // Simulated user data - in real app, this would come from a database
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // In a real application, you would implement proper pagination here

    res.json({
      data: users,
      pagination: {
        page,
        limit,
        total: users.length,
        totalPages: Math.ceil(users.length / limit)
      }
    });
  } catch (error) {
    next(error);
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  // Log the error (in production, use a proper logging service)
  console.error('Error:', err);

  // Handle different types of errors
  if (err.name === 'ValidationError') {
    return res.status(err.statusCode).json({
      error: err.message
    });
  }

  if (err.name === 'AuthenticationError') {
    return res.status(err.statusCode).json({
      error: 'Authentication failed'
    });
  }

  // Handle JSON parsing errors
  if (err instanceof SyntaxError && err.status === 400 && 'body' in err) {
    return res.status(400).json({
      error: 'Invalid JSON in request body'
    });
  }

  // Handle all other errors
  res.status(500).json({
    error: 'Internal server error'
  });
});

// Handle 404 routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found'
  });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);

  // In production, don't display detailed error messages
  if (process.env.NODE_ENV !== 'development') {
    console.log('Server is running in production mode');
  }
});

module.exports = app;

