const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');
const { body, query, validationResult } = require('express-validator');

const app = express();

// Security middleware
app.use(helmet()); // Security headers
app.use(helmet.hidePoweredBy());

// CORS configuration
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true,
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);

// Body parsing with limits to prevent DOS attacks
app.use(express.json({
  limit: '10kb',
  strict: true
}));

app.use(express.urlencoded({
  extended: true,
  limit: '10kb'
}));

// Enhanced health check with input validation
app.get('/health', [
  // Validate query parameters if present
  query('detailed').optional().isBoolean().withMessage('Detailed must be a boolean'),
], (req, res) => {
  // Check for validation errors
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ 
      error: 'Validation failed', 
      details: errors.array() 
    });
  }

  try {
    const healthData = {
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
    };

    // Add detailed info if requested
    if (req.query.detailed === 'true') {
      healthData.hostname = require('os').hostname();
      healthData.platform = process.platform;
      healthData.memory = process.memoryUsage();
    }

    res.json(healthData);
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      message: 'Failed to retrieve health status'
    });
  }
});

// Users endpoint with validation and pagination
app.get('/users', [
  // Input validation
  query('page').optional().isInt({ min: 1 }).withMessage('Page must be a positive integer'),
  query('limit').optional().isInt({ min: 1, max: 100 }).withMessage('Limit must be between 1 and 100'),
  query('search').optional().isString().trim().escape().withMessage('Search must be a valid string'),
], (req, res) => {
  // Validate input
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ 
      error: 'Validation failed', 
      details: errors.array() 
    });
  }

  try {
    // Mock user data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Extract query parameters with defaults
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 10;
    const search = req.query.search?.toLowerCase();

    // Filter users if search parameter provided
    let filteredUsers = users;
    if (search) {
      filteredUsers = users.filter(user => 
        user.name.toLowerCase().includes(search) || 
        user.email.toLowerCase().includes(search)
      );
    }

    // Simple pagination
    const startIndex = (page - 1) * limit;
    const endIndex = page * limit;
    const paginatedUsers = filteredUsers.slice(startIndex, endIndex);

    // Response with pagination metadata
    res.json({
      data: paginatedUsers,
      pagination: {
        currentPage: page,
        totalPages: Math.ceil(filteredUsers.length / limit),
        totalItems: filteredUsers.length,
        itemsPerPage: limit,
        hasNext: endIndex < filteredUsers.length,
        hasPrev: startIndex > 0
      }
    });

  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      message: 'Failed to retrieve users'
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found',
    message: `The requested endpoint '${req.originalUrl}' does not exist.`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  res.status(500).json({
    error: 'Internal server error',
    message: 'An unexpected error occurred'
  });
});

// Use environment variable for port, with fallback
const PORT = process.env.PORT || 3000;

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
  });
});

module.exports = app;

