async function testDatabaseConnection() {
  console.log('Testing database connection...');

  try {
    const client = new Client({
      connectionString: process.env.DATABASE_URL,
      ssl: false // Explicitly disable SSL for testing
    });

    await client.connect();
    const result = await client.query('SELECT NOW()');
    console.log('✅ Database connection successful!');
    console.log('Current time:', result.rows[0].now);
    await client.end();
    return true;
  } catch (error) {
    console.log('❌ Database connection failed:', error.message);
    return false;
  }
}

function testApiKey(url, apiKey, name) {
  return new Promise((resolve) => {
    console.log(`\nTesting ${name} API key...`);

    const options = {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
      }
    };

    // Add authorization header based on the API
    if (name === 'Anthropic') {
      options.headers['x-api-key'] = apiKey;
    } else if (name === 'Stripe') {
      options.headers['Authorization'] = `Bearer ${apiKey}`;
    } else if (name === 'Logfire') {
      // Logfire uses the token as a query parameter or header
      options.headers['Authorization'] = `Bearer ${apiKey}`;
    }

    const request = https.request(url, options, (response) => {
      let data = '';
      response.on('data', (chunk) => {
        data += chunk;
      });

      response.on('end', () => {
        if (response.statusCode >= 200 && response.statusCode < 300) {
          console.log(`✅ ${name} API key is valid! Status: ${response.statusCode}`);
          console.log(`Response: ${data.substring(0, 100)}...`);
          resolve(true);
        } else {
          console.log(`❌ ${name} API key invalid or unauthorized. Status: ${response.statusCode}`);
          console.log(`Response: ${data}`);
          resolve(false);
        }
      });
    });

    request.on('error', (error) => {
      console.log(`❌ ${name} API test failed:`, error.message);
      resolve(false);
    });

    request.setTimeout(10000, () => {
      request.destroy();
      console.log(`❌ ${name} API test timed out`);
      resolve(false);
    });

    request.end();
  });
}

