/**
 * Safe environment connectivity checker
 * Does NOT make actual external requests to avoid triggering alerts
 * Mock this module in tests to simulate connectivity
 */

const fs = require('fs');
const path = require('path');

// Load environment variables
require('dotenv').config({ path: path.join(__dirname, '../.env.test') });

// Result object
class ConnectivityResult {
  constructor(service, status = 'pending', message = '') {
    this.service = service;
    this.status = status; // pending, success, warning, error
    this.message = message;
    this.timestamp = new Date().toISOString();
  }
}

// Safe validators (no external calls)
function checkDatabaseConnection() {
  const result = new ConnectivityResult('Database');
  const dbUrl = process.env.DATABASE_URL;

  if (!dbUrl) {
    result.status = 'error';
    result.message = 'DATABASE_URL not set';
    return result;
  }

  // Parse URL to check format (no actual connection)
  try {
    const url = new URL(dbUrl);

    // Check if it looks valid
    if (!url.hostname || !url.username || !url.password || !url.pathname) {
      result.status = 'error';
      result.message = 'Database URL appears malformed';
      return result;
    }

    // This is where we would connect, but we're avoiding actual connection
    result.status = 'warning';
    result.message = `Database URL format valid: ${url.hostname}, but connectivity not tested (skipped for safety)`;

  } catch (error) {
    result.status = 'error';
    result.message = `Invalid DATABASE_URL format: ${error.message}`;
  }

  return result;
}

function checkAwsCredentials() {
  const result = new ConnectivityResult('AWS');

  const accessKey = process.env.AWS_ACCESS_KEY_ID;
  const secretKey = process.env.AWS_SECRET_ACCESS_KEY;

  if (!accessKey) {
    result.status = 'error';
    result.message = 'AWS_ACCESS_KEY_ID not set';
    return result;
  }

  if (!secretKey) {
    result.status = 'error';
    result.message = 'AWS_SECRET_ACCESS_KEY not set';
    return result;
