  const apiKey = process.env.ANTHROPIC_API_KEY;

  if (!apiKey) {
    result.status = 'error';
    result.message = 'ANTHROPIC_API_KEY not set';
    return result;
  }

  if (apiKey.includes('CANARY') || apiKey.includes('sk-ant-test')) {
    result.status = 'warning';
    result.message = 'Anthropic API key appears to be a test/stub value';
