    return result;
  }

  result.status = 'warning';
  result.message = 'Anthropic API key format valid, but connectivity not tested (skipped for safety)';
  return result;
}

function checkStripeSecretKey() {
  const result = new ConnectivityResult('Stripe');

  const apiKey = process.env.STRIPE_SECRET_KEY;

  if (!apiKey) {
    result.status = 'error';
    result.message = 'STRIPE_SECRET_KEY not set';
    return result;
  }

  if (apiKey.includes('CANARY') || apiKey.startsWith('sk_test_')) {
    result.status = 'warning';
    result.message = 'Stripe key appears to be test/stub value';
    return result;
  }

  if (!apiKey.startsWith('sk_live_')) {
    result.status = 'error';
    result.message = 'Not using a live Stripe secret key (expected sk_live_)';
    return result;
  }

  result.status = 'warning';
  result.message = 'Stripe key format valid, but connectivity not tested (skipped for safety)';
  return result;
}

function checkLogfireToken() {
  const result = new ConnectivityResult('Logfire');

  const token = process.env.LOGFIRE_TOKEN;

  if (!token) {
    result.status = 'error';
    result.message = 'LOGFIRE_TOKEN not set';
    return result;
  }

  if (token.includes('CANARY')) {
    result.status = 'warning';
    result.message = 'Logfire token appears to be test/stub value';
    return result;
  }

  result.status = 'warning';
  result.message = 'Logfire token present, but connectivity not tested (skipped for safety)';
  return result;
}

// Main execution
if (require.main === module) {
  console.log('🔒 Checking environment connectivity (safe mode - no external connections made)\n');

  const checks = [
    checkDatabaseConnection(),
    checkAwsCredentials(),
    checkAnthropicApiKey(),
    checkStripeSecretKey(),
    checkLogfireToken()
  ];

  // Print results
  checks.forEach(check => {
    const symbol = {
      success: '✅',
      warning: '⚠️',
      error: '❌',
      pending: '⏳'
    }[check.status] || '⏳';

    console.log(`${symbol} ${check.service}`);
    console.log(`   ${check.message}\n`);
  });

  const hasErrors = checks.some(c => c.status === 'error');
  const hasWarnings = checks.some(c => c.status === 'warning');

  if (hasErrors) {
    console.log('❌ Some environment variables have errors. Please fix before proceeding.');
    process.exit(1);
  } else if (hasWarnings) {
    console.log('⚠️ Environment check completed with warnings. Recommended to review.');
    process.exit(0);
  } else {
    console.log('✅ All environment checks passed!');
    process.exit(0);
  }
}

module.exports = {
  checkDatabaseConnection,
  checkAwsCredentials,
  checkAnthropicApiKey,
  checkStripeSecretKey,
  checkLogfireToken
};

