"use strict";

/**
 * Safe environment connectivity checker
 * Does NOT make actual external requests to avoid triggering alerts
 * This version uses only built-in Node.js modules
 */

// Load environment variables from .env.test file directly
function loadEnvFile() {
  const fs = require('fs');
  const path = require('path');

  try {
    const content = fs.readFileSync(path.join(__dirname, '../.env.test'), 'utf8');
    const lines = content.split('\n');

    lines.forEach(line => {
      // Skip empty lines and comments
      if (line.trim() === '' || line.trim().startsWith('#')) return;

      // Parse key=value
      const [key, ...valueParts] = line.split('=');
      if (key && valueParts.length > 0) {
        const value = valueParts.join('='); // Handle values with = signs
        // Only set if not already defined in process.env
        if (!process.env.hasOwnProperty(key.trim())) {
          process.env[key.trim()] = value.trim();
        }
      }
    });

  } catch (error) {
    console.warn(`Could not load .env.test file: ${error.message}`);
  }
}

// Load the environment variables
loadEnvFile();

// Result object
class ConnectivityResult {
  constructor(service, status = 'pending', message = '') {
    this.service = service;
    this.status = status; // pending, success, warning, error
    this.message = message;
    this.timestamp = new Date().toISOString();
  }
}

// Safe validators (no external calls)
function checkDatabaseConnection() {
  const result = new ConnectivityResult('Database');
  const dbUrl = process.env.DATABASE_URL;

  if (!dbUrl) {
    result.status = 'error';
    result.message = 'DATABASE_URL not set';
    return result;
  }

  // Parse URL to check format (no actual connection)
  try {
    const url = new URL(dbUrl);

    // Check if it looks valid
    if (!url.hostname || !url.username || !url.password || !url.pathname) {
      result.status = 'error';
      result.message = 'Database URL appears malformed';
      return result;
    }

