      if (search.length > 100) {
        return res.status(400).json({
          error: 'Search query too long',
          timestamp: new Date().toISOString()
        });
      }
      const searchTerm = search.toLowerCase();
      filteredUsers = mockUsers.filter(user => 
        user.name.toLowerCase().includes(searchTerm) || 
        user.email.toLowerCase().includes(searchTerm)
      );
    }

    // Apply pagination
    const startIndex = (validatedPage - 1) * validatedLimit;
    const paginatedUsers = filteredUsers.slice(startIndex, startIndex + validatedLimit);

    // Return enriched response with metadata
    res.json({
      data: paginatedUsers,
      pagination: {
        page: validatedPage,
        limit: validatedLimit,
        total: filteredUsers.length,
        pages: Math.ceil(filteredUsers.length / validatedLimit)
      },
      timestamp: new Date().toISOString()
    });

  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      message: 'An unexpected error occurred',
      timestamp: new Date().toISOString()
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found',
    path: req.path,
    method: req.method,
    timestamp: new Date().toISOString()
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  // Determine status code based on error type
  const statusCode = error.statusCode || error.status || 500;

  res.status(statusCode).json({
    error: 'Internal server error',
    message: process.env.NODE_ENV === 'production' 
      ? 'An unexpected error occurred'
      : error.message,
    timestamp: new Date().toISOString()
  });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

module.exports = app;

