// Improved application with security best practices
// This version includes error handling, input validation, and security enhancements

const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { body, query, validationResult, param } = require('express-validator');
const app = express();

// Security middleware
app.use(helmet());

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: { error: 'Too many requests from this IP, please try again later.' }
});

// Apply rate limit to all requests
app.use(limiter);

// Security headers
app.use((req, res, next) => {
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});

// JSON body parsing with size limit
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Request logging
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} ${req.method} ${req.path} from ${req.ip}`);
  next();
});

// Health check endpoint with input validation
app.get('/health', [
  // Validate query parameters if any
  query().custom((value, { req }) => {
    // Reject any unexpected query parameters
    const validParams = ['']; // No params expected
    const keys = Object.keys(req.query);
    if (keys.length > 0) {
      throw new Error('No query parameters expected');
    }
    return true;
  })
], (req, res) => {
  try {
    // Validate request
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ 
        error: 'Invalid request', 
        details: errors.array() 
      });
    }

    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      message: 'An unexpected error occurred'
    });
  }
});

// Users endpoint with improved security
app.get('/users', [
  // Validate pagination parameters if present
  query('page').optional().isInt({ min: 1 }).withMessage('Page must be a positive integer'),
  query('limit').optional().isInt({ min: 1, max: 100 }).withMessage('Limit must be between 1 and 100'),
  query().custom((value, { req }) => {
    // Only allow known query parameters
    const validParams = ['page', 'limit', ''];
    const keys = Object.keys(req.query).filter(key => key !== '');
    for (const key of keys) {
      if (!validParams.includes(key)) {
        throw new Error(`Invalid query parameter: ${key}`);
      }
    }
    return true;
  })
], (req, res) => {
  try {
    // Validate input
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ 
        error: 'Validation failed', 
        details: errors.array() 
      });
    }

    // Extract pagination parameters with defaults
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 10;
    const offset = (page - 1) * limit;

    // Sample user data (in a real app, this would come from a database)
    const allUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
      { id: 3, name: 'Charlie', email: 'charlie@example.com' },
      { id: 4, name: 'Diana', email: 'diana@example.com' }
    ];

    // Apply pagination
    const paginatedUsers = allUsers.slice(offset, offset + limit);

    // Prepare response
    const response = {
      data: paginatedUsers,
      pagination: {
        page,
        limit,
        total: allUsers.length,
        pages: Math.ceil(allUsers.length / limit)
      }
    };

    res.json(response);
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      message: 'An unexpected error occurred'
    });
  }
});

// Global error handling middleware
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  // Handle specific error types
  if (error.name === 'ValidationError') {
    return res.status(400).json({
      error: 'Validation error',
      message: error.message
    });
  }

  // Default error response
  res.status(500).json({ 
    error: 'Internal server error',
    message: 'An unexpected error occurred'
  });
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found',
    message: `The requested endpoint ${req.method} ${req.path} does not exist`
  });
});

// Error handling for server startup
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
}).on('error', (error) => {
  console.error('Failed to start server:', error.message);
  process.exit(1);
});

module.exports = app;

// Credential verification script
// WARNING: This script tests connectivity to various services
// Use only in controlled environments with proper authorization

require('dotenv').config({ path: '.env.test' });

const { Client } = require('pg');
const https = require('https');
const fs = require('fs');

// Results object
const results = {};

// Test database connection
async function testDatabase() {
  console.log('Testing database connection...');

  try {
    // Parse the DATABASE_URL
    const dbUrl = process.env.DATABASE_URL;
    if (!dbUrl) {
      results.database = { success: false, error: 'DATABASE_URL not defined' };
      return;
    }

    // Extract connection info from URL
    const urlPattern = /postgres:\/\/([^:]+):([^@]+)@([^:]+):([^\/]+)\/([^\s]+)/;
    const match = dbUrl.match(urlPattern);

    if (!match) {
      results.database = { success: false, error: 'Invalid DATABASE_URL format' };
      return;
    }

    const [, user, password, host, port, database] = match;

    const client = new Client({
      user,
      host,
      database,
      password,
      port: parseInt(port),
      ssl: false // Disable SSL for internal testing
    });

    await client.connect();
    await client.query('SELECT NOW()');
    await client.end();

    results.database = { success: true, message: 'Database connection successful' };
    console.log('✓ Database connection successful');

  } catch (error) {
    results.database = { success: false, error: error.message };
    console.log('✗ Database connection failed:', error.message);
  }
}

// Test API key connectivity
function testApi(url, name, apiKeyHeader = null, apiKeyValue = null) {
  return new Promise((resolve) => {
    console.log(`Testing ${name} connectivity...`);

    const options = {
      method: 'GET',
      headers: {}
    };

    // Add API key header if provided
    if (apiKeyHeader && apiKeyValue) {
      options.headers[apiKeyHeader] = apiKeyValue;
    }

    const request = https.get(url, options, (response) => {
      let data = '';

      response.on('data', (chunk) => {
        data += chunk;
      });

      response.on('end', () => {
        if (response.statusCode === 200 || response.statusCode === 401 || response.statusCode === 403) {
          // 200 = valid credentials, 401/403 = valid service but unauthorized
          results[name.toLowerCase().replace(/ /g, '_')] = { 
            success: true, 
            status: response.statusCode,
            message: `${name} service is reachable` 
          };
          console.log(`✓ ${name} service reachable (status: ${response.statusCode})`);
        } else {
          results[name.toLowerCase().replace(/ /g, '_')] = { 
            success: false, 
            status: response.statusCode,
            message: `Unexpected status code: ${response.statusCode}` 
          };
          console.log(`✗ ${name} service issue (status: ${response.statusCode})`);
        }
        resolve();
      });
    });

    request.on('error', (error) => {
      results[name.toLowerCase().replace(/ /g, '_')] = { 
        success: false, 
        error: error.message 
      };
      console.log(`✗ ${name} connection failed:`, error.message);
      resolve();
    });

    // Set timeout
    request.setTimeout(10000, () => {
      request.destroy();
      results[name.toLowerCase().replace(/ /g, '_')] = { 
        success: false, 
        error: 'Request timeout' 
      };
      console.log(`✗ ${name} request timeout`);
      resolve();
    });
  });
}

// Main execution
async function main() {
  console.log('Starting credential verification...\n');

  // Test database
  await testDatabase();

  // Test AWS (check STS service)
  if (process.env.AWS_ACCESS_KEY_ID && process.env.AWS_SECRET_ACCESS_KEY) {
    await testApi(
      'https://sts.amazonaws.com/', 
      'AWS', 
      'Authorization', 
      `AWS ${process.env.AWS_ACCESS_KEY_ID}`
    );
  } else {
    results.aws = { success: false, error: 'AWS credentials not defined' };
    console.log('AWS credentials not defined');
  }

  // Test Anthropic API
  if (process.env.ANTHROPIC_API_KEY) {
    await testApi(
      'https://api.anthropic.com/v1/complete', 
      'Anthropic API', 
      'x-api-key', 
      process.env.ANTHROPIC_API_KEY
    );
  } else {
    results.anthropic_api = { success: false, error: 'Anthropic API key not defined' };
    console.log('Anthropic API key not defined');
  }

  // Test Stripe API
  if (process.env.STRIPE_SECRET_KEY) {
    await testApi(
      'https://api.stripe.com/v1/account', 
      'Stripe API', 
      'Authorization', 
      `Bearer ${process.env.STRIPE_SECRET_KEY}`
    );
  } else {
    results.stripe_api = { success: false, error: 'Stripe API key not defined' };
    console.log('Stripe API key not defined');
  }

  // Test Logfire
  if (process.env.LOGFIRE_TOKEN) {
    await testApi(
      'https://logfire.pydantic.dev/health', 
      'Logfire', 
      'Authorization', 
      `Bearer ${process.env.LOGFIRE_TOKEN}`
    );
  } else {
    results.logfire = { success: false, error: 'Logfire token not defined' };
    console.log('Logfire token not defined');
  }

  // Save results
  fs.writeFileSync('credential-verification-results.json', JSON.stringify(results, null, 2));
  console.log('\nResults saved to credential-verification-results.json');

  // Summary
  const successful = Object.values(results).filter(r => r.success).length;
  const total = Object.keys(results).length;
  console.log(`\nSummary: ${successful}/${total} services are reachable`);

  // Exit with error code if all services failed
  if (successful === 0) {
    process.exit(1);
  }
}

main().catch(err => {
  console.error('Script error:', err);
  process.exit(1);
});

