  for (const [requestKey, data] of requestCounts) {
    if (now - data.timestamp > WINDOW_MS) {
      requestCounts.delete(requestKey);
    }
  }

  const requestKey = `${ip}:${req.path}`;
  const requestData = requestCounts.get(requestKey) || { count: 0, timestamp: now };

