// Read the .env.test file
const envTestPath = path.join(__dirname, '.env.test');

function validateCredentials() {
  try {
    const envContent = fs.readFileSync(envTestPath, 'utf8');
    const lines = envContent.split('\n');

    const results = {};

    for (const line of lines) {
      // Skip empty lines and comments
      if (!line.trim() || line.trim().startsWith('#')) continue;

      const [key, value] = line.split('=');
      if (!key || !value) continue;

      results[key.trim()] = validateSingleCredential(key.trim(), value.trim());
    }

    // Print results
    console.log('CREDENTIAL VALIDATION RESULTS\n');
    console.log('='.repeat(50));

    let validCount = 0;
    let invalidCount = 0;

    for (const [key, result] of Object.entries(results)) {
      console.log(`>${key}<`);
      console.log(`Status: ${result.isValid ? 'VALID' : 'INVALID'}`);
      console.log(`Message: ${result.message}`);

      if (result.suggestion) {
        console.log(`Suggestion: ${result.suggestion}`);
      }

      console.log('-'.repeat(30));

      if (result.isValid) validCount++;
      else invalidCount++;
    }

    console.log(`\nSUMMARY: ${validCount} valid, ${invalidCount} potentially problematic`);
    console.log('NOTE: This is only format validation. Actual connectivity not tested for security reasons.');

    return results;
  } catch (error) {
    console.error('Error reading .env.test file:', error.message);
    return {};
  }
}

function validateSingleCredential(key, value) {
  // Check for obviously missing or placeholder values
  if (!value || value === '' || value === 'your-key-here' || value.includes('your-') || value.includes('{') || value.includes('}')) {
    return {
      isValid: false,
      message: 'Missing or placeholder value',
      suggestion: 'Replace with actual credential'
    };
  }

  // Check for canary values
  if (value.includes('CANARY') || value.includes('fake') || value.includes('mock')) {
    return {
      isValid: false,
      message: 'Appears to be a canary/test value',
      suggestion: 'Verify if this should be replaced with real credential'
    };
  }

  // Validate database URL format
  if (key === 'DATABASE_URL') {
    if (value.startsWith('postgres://') || value.startsWith('postgresql://')) {
      return {
        isValid: true,
        message: 'Valid PostgreSQL URL format',
        suggestion: 'Consider using environment-specific configuration'
      };
    } else {
      return {
        isValid: false,
        message: 'Invalid database URL format',
        suggestion: 'Should start with postgres:// or postgresql://'
      };
    }
  }

  // Validate AWS key format
  if (key === 'AWS_ACCESS_KEY_ID') {
    if (/^AKIA[0-9A-Z]{16}$/.test(value)) {
      return {
        isValid: true,
        message: 'Valid AWS access key format',
        suggestion: 'Ensure this has appropriate IAM permissions'
      };
    } else {
      return {
        isValid: false,
        message: 'Invalid AWS access key format',
        suggestion: 'Should be 20 characters, starting with AKIA'
      };
    }
  }

  // Validate AWS secret format
  if (key === 'AWS_SECRET_ACCESS_KEY') {
    if (/^[0-9a-zA-Z/+=]{40}$/.test(value)) {
      return {
        isValid: true,
        message: 'Valid AWS secret key format',
        suggestion: 'Store in secure parameter store if possible'
      };
    } else {
      return {
        isValid: false,
        message: 'Invalid AWS secret key format',
        suggestion: 'Should be 40 characters'
      };
    }
  }

  // Validate Anthropic API key format
  if (key === 'ANTHROPIC_API_KEY') {
    if (value.startsWith('sk-ant-') && value.length > 10) {
      return {
        isValid: true,
        message: 'Valid Anthropic API key format',
        suggestion: 'Rotate key periodically for security'
      };
    } else {
      return {
        isValid: false,
        message: 'Invalid Anthropic API key format',
        suggestion: 'Should start with sk-ant-'
      };
    }
  }

  // Validate Stripe secret key format
  if (key === 'STRIPE_SECRET_KEY') {
    if ((value.startsWith('sk_live_') || value.startsWith('sk_test_')) && value.length > 10) {
