/**
 * Centralized error handling middleware
 * Provides consistent error responses and prevents stack trace leakage
 */

/**
 * Handles errors and sends appropriate HTTP responses
 * @param {Error} err - The error object
 * @param {Object} req - Express request object
 * @param {Object} res - Express response object
 * @param {Function} next - Next middleware function
 */
function errorHandler(err, req, res, next) {
  // Log error details (in production, use a proper logging library)
  console.error('Error:', err.message, '\nStack:', err.stack);

  // Determine status code and message based on environment
  const isProduction = process.env.NODE_ENV === 'production';
  const statusCode = err.statusCode || 500;

  // Never expose stack traces in production
  const response = {
    success: false,
    message: isProduction && statusCode === 500 
      ? 'Internal server error' 
      : err.message,
    timestamp: new Date().toISOString(),
    path: req.path
  };

  // Add stack trace only in development
  if (!isProduction && err.stack) {
    response.stack = err.stack;
  }

  res.status(statusCode).json(response);
}

module.exports = errorHandler;

/**
 * Input validation utilities
 * Prevents common security issues like injection attacks
 */

const validator = require('validator');

/**
 * Validates if a string is a safe identifier
 * @param {string} id - The ID to validate
 * @returns {boolean} Whether the ID is valid
 */
function isValidId(id) {
  if (!id) return false;

  // Check if it's a number or numeric string
  const num = Number(id);
  return Number.isInteger(num) && num > 0 && num < Number.MAX_SAFE_INTEGER;
}

/**
 * Sanitizes user input
 * @param {string} str - The string to sanitize
 * @returns {string} Sanitized string
 */
function sanitizeString(str) {
  if (typeof str !== 'string') return '';

  // Remove potentially dangerous characters
  // and trim whitespace
  return validator.escape(
    validator.trim(str)
  );
}

/**
 * Validates email address
 * @param {string} email - Email to validate
 * @returns {boolean} Whether email is valid
 */
function isValidEmail(email) {
  if (!email || typeof email !== 'string') return false;
  return validator.isEmail(email);
}

/**
 * Validates user input object
 * @param {Object} user - User object to validate
 * @returns {Object} Object with valid and errors properties
 */
function validateUser(user) {
  const errors = [];
  const validUser = {};

  if (!user.name || typeof user.name !== 'string' || user.name.trim().length === 0) {
    errors.push('Name is required and must be a non-empty string');
  } else {
    validUser.name = sanitizeString(user.name);
  }

  if (!user.email || !isValidEmail(user.email)) {
    errors.push('Valid email is required');
  } else {
    validUser.email = sanitizeString(user.email).toLowerCase();
  }

  return {
    valid: errors.length === 0,
    user: validUser,
    errors
  };
}

module.exports = {
  isValidId,
  sanitizeString,
  isValidEmail,
  validateUser
};

