const validateUserId = (req, res, next) => {
  const { id } = req.params;

  // Basic validation
  if (id && (isNaN(id) || parseInt(id) <= 0)) {
    return res.status(400).json({
      error: 'Invalid user ID format'
    });
  }
  next();
};

app.get('/health', (req, res) => {
  // Input validation for query parameters if any
  const allowedFields = ['verbose', 'detailed'];
  const queryFields = Object.keys(req.query);

  for (const field of queryFields) {
    if (!allowedFields.includes(field)) {
      return res.status(400).json({
        error: `Query parameter '${field}' is not allowed`
      });
    }
  }

  res.json({ 
    status: 'ok', 
    timestamp: new Date().toISOString(),
    ...(req.query.verbose && { version: '1.0.0' }),
    ...(req.query.detailed && { uptime: process.uptime() })
  });
});

app.get('/users', (req, res) => {
  // In a real application, you'd want to add pagination and filtering validation
  const page = req.query.page ? parseInt(req.query.page) : 1;
  const limit = req.query.limit ? parseInt(req.query.limit) : 10;

  // Validate pagination parameters
  if ((req.query.page && isNaN(page)) || page < 1) {
    return res.status(400).json({
      error: 'Page parameter must be a positive integer'
    });
  }

  if ((req.query.limit && isNaN(limit)) || limit < 1 || limit > 100) {
    return res.status(400).json({
      error: 'Limit parameter must be between 1 and 100'
    });
  }

  // Simulated database response with pagination
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  // Apply pagination (simplified)
  const startIndex = (page - 1) * limit;
  const results = users.slice(startIndex, startIndex + limit);

  res.json({
    data: results,
    pagination: {
      page,
      limit,
      total: users.length,
      pages: Math.ceil(users.length / limit)
    }
  });
});

// Error handling middleware
