const validateParams = (req, res, next) => {
  // Check for suspicious query parameters
  const suspiciousPatterns = ["<script>", "javascript:", "onerror=", "onload=", "\x"];

  // Validate query parameters
  for (const [key, value] of Object.entries(req.query)) {
    if (typeof value === 'string') {
      // Check for potential XSS attempts
      if (suspiciousPatterns.some(pattern => 
        value.toLowerCase().includes(pattern))) {
        return res.status(400).json({
          error: 'Invalid request - suspicious content detected'
        });
      }

      // Check for SQL injection patterns
      const sqlPatterns = ['SELECT', 'UNION', 'DROP', 'DELETE', 'INSERT', 'UPDATE'];
      if (sqlPatterns.some(pattern => 
        value.toUpperCase().includes(pattern) && 
        value.toUpperCase().includes(' FROM '))) {
        return res.status(400).json({
          error: 'Invalid request - potential SQL injection detected'
        });
      }
    }
  }
  next();
};

